"""Load SD3.5 latent data generated by ``generate_consistency_data.py``.

On-disk layout::

    samples/0000/00000123.pt
    # {"latents", "prompt_embeds", "pooled_embeds", "prompt"}

    data_root/
    ├── metadata.jsonl
    └── samples/...
"""

from __future__ import annotations

import json
import logging
import os
from typing import Any, Optional

import torch
from torch.utils.data import DataLoader, Dataset, DistributedSampler

logger = logging.getLogger(__name__)

class LatentPromptDataset(Dataset):
    """Dataset reading the consistency-data layout from
    :mod:`scripts.generate_consistency_data`.

    Args:
        data_root: Root directory containing ``metadata.jsonl`` and ``samples/``.
        max_samples: If > 0, truncate to the first ``max_samples`` entries.
        load_pooled: If False, skip loading ``pooled_embeds``.
        validate_existence: If True, drop metadata entries whose sample file
            is missing (slow on huge datasets; default off).
    """

    def __init__(
        self,
        data_root: str,
        max_samples: int = -1,
        load_pooled: bool = True,
        validate_existence: bool = False,
    ):
        self.data_root = os.path.abspath(data_root)
        self.load_pooled = bool(load_pooled)

        meta_path = os.path.join(self.data_root, "metadata.jsonl")
        if not os.path.exists(meta_path):
            raise FileNotFoundError(
                f"metadata.jsonl not found at {meta_path}. "
                f"Did you run scripts/generate_consistency_data.py first?"
            )
        self.entries: list[dict[str, Any]] = []
        with open(meta_path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                item = json.loads(line)
                if "file" not in item:
                    raise ValueError(
                        f"metadata.jsonl entry missing required 'file' key: {item}"
                    )
                if (
                    os.path.splitext(item["file"])[1].lower() != ".pt"
                    or item.get("format", "latent") != "latent"
                ):
                    raise ValueError(
                        "LatentPromptDataset only accepts latent .pt entries; "
                        f"got {item!r}."
                    )
                self.entries.append(item)

        if max_samples is not None and max_samples > 0:
            self.entries = self.entries[:max_samples]

        if validate_existence:
            kept = [
                e for e in self.entries
                if os.path.exists(os.path.join(self.data_root, e["file"]))
            ]
            n_dropped = len(self.entries) - len(kept)
            if n_dropped > 0:
                logger.warning(
                    f"LatentPromptDataset: dropped {n_dropped} entries with "
                    f"missing sample files (out of {len(self.entries)})."
                )
            self.entries = kept

        if len(self.entries) == 0:
            raise RuntimeError(
                f"LatentPromptDataset: no usable entries found under {self.data_root}."
            )

        logger.info(
            f"LatentPromptDataset: loaded {len(self.entries)} latent entries "
            f"from {self.data_root}"
        )

    def __len__(self) -> int:
        return len(self.entries)

    def __getitem__(self, idx: int) -> dict[str, Any]:
        entry = self.entries[idx]
        path = os.path.join(self.data_root, entry["file"])
        prompt = entry.get("prompt", "")

        try:
            data = torch.load(path, map_location="cpu", weights_only=False)
        except FileNotFoundError as exc:
            raise FileNotFoundError(
                f"Sample file missing for id={entry.get('id', idx)}: {path}. "
                f"Re-run scripts/generate_consistency_data.py with --no_resume "
                f"to regenerate, or list-validate the dataset before training."
            ) from exc

        out: dict[str, Any] = {
            "latents": data["latents"],
            "prompt_embeds": data["prompt_embeds"],
            "prompt": data.get("prompt", prompt),
        }
        if self.load_pooled:
            out["pooled_embeds"] = data["pooled_embeds"]
        return out


def _collate_latent_prompt(batch: list[dict[str, Any]]) -> dict[str, Any]:
    """Stack tensor fields, gather string prompts into a list."""
    out: dict[str, Any] = {}
    if "prompt" in batch[0]:
        out["prompt"] = [item["prompt"] for item in batch]

    for k in ("latents", "prompt_embeds", "pooled_embeds"):
        if k not in batch[0]:
            continue
        try:
            out[k] = torch.stack([item[k] for item in batch], dim=0)
        except RuntimeError as exc:
            shapes = {i: tuple(item[k].shape) for i, item in enumerate(batch)}
            raise RuntimeError(
                f"LatentPromptDataset collate: shape mismatch for key {k!r}: {shapes}"
            ) from exc
    return out


def create_latent_prompt_dataloader(
    data_root: str,
    batch_size: int,
    distributed: bool = True,
    seed: int = 42,
    max_samples: int = -1,
    load_pooled: bool = True,
    num_workers: int = 0,
    drop_last: bool = True,
    pin_memory: bool = True,
) -> tuple[DataLoader, Optional[DistributedSampler]]:
    """Factory mirroring ``meanflownft.data.prompt_dataset.create_prompt_dataloader``.

    Returns ``(dataloader, sampler_or_None)``. Sampler is returned so the base
    trainer can call ``sampler.set_epoch(epoch)`` for resume-deterministic
    shuffle.
    """
    dataset = LatentPromptDataset(
        data_root=data_root,
        max_samples=max_samples,
        load_pooled=load_pooled,
    )

    sampler: Optional[DistributedSampler] = None
    if distributed:
        sampler = DistributedSampler(dataset, shuffle=True, seed=seed)

    loader = DataLoader(
        dataset,
        batch_size=batch_size,
        sampler=sampler,
        shuffle=(sampler is None),
        num_workers=num_workers,
        drop_last=drop_last,
        pin_memory=pin_memory,
        collate_fn=_collate_latent_prompt,
    )
    return loader, sampler
